parameters.jsCode:
const input = $input.first().json;

// Slack usually sends interactive payload as form field: payload
let payloadRaw =
  input.body?.payload ||
  input.payload ||
  input.body;

let payload;

try {
  payload = typeof payloadRaw === 'string'
    ? JSON.parse(payloadRaw)
    : payloadRaw;
} catch (error) {
  throw new Error(`Could not parse Slack payload: ${error.message}`);
}

const clickedAction = payload.actions?.[0];

if (!clickedAction?.value) {
  throw new Error('No Slack action value found.');
}

const [ticket_id, decision] = clickedAction.value.split('|');

return [
  {
    json: {
      ticket_id,
      decision,
      action_id: clickedAction.action_id,
      clicked_by_id: payload.user?.id || '',
      clicked_by_name: payload.user?.username || payload.user?.name || '',
      slack_channel: payload.channel?.id || '',
      slack_message_ts: payload.message?.ts || '',
      response_url: payload.response_url || '',
      original_message_text: payload.message?.text || ''
    }
  }
];

